link.script:
// Shared wiring for all three builds. The chart instance is reached by its
// chart.id, so vanilla, React and Vue share one implementation. Returns a
// cleanup function once the chart exists, or null while it is still rendering.
function wireCustomLegend() {
  var chart = ApexCharts.getChartByID('customLegend')
  if (!chart) return null

  var allLegends = document.querySelectorAll(".legend input[type='checkbox']")

  // On load, hide any series whose checkbox starts unchecked.
  for (var i = 0; i < allLegends.length; i++) {
    if (!allLegends[i].checked) chart.toggleSeries(allLegends[i].value)
  }

  // toggleSeries accepts the series name to toggle; the value attribute holds it.
  var handlers = []
  allLegends.forEach(function (cb) {
    var fn = function () {
      chart.toggleSeries(cb.value)
    }
    cb.addEventListener('change', fn)
    handlers.push({ cb: cb, fn: fn })
  })

  return function () {
    handlers.forEach(function (h) {
      h.cb.removeEventListener('change', h.fn)
    })
  }
}

chart.options:
chart: {
  id: 'customLegend',
  height: 310,
  type: 'line',
  stacked: false,
},
stroke: {
  width: [0, 2, 5],
  curve: 'smooth'
},
plotOptions: {
  bar: {
    columnWidth: '50%'
  }
},
fill: {
  opacity: [0.85,0.25,1],
  gradient: {
    inverseColors: false,
    shade: 'light',
    type: "vertical",
    opacityFrom: 0.85,
    opacityTo: 0.55,
    stops: [0, 100, 100, 100]
  }
},
labels: ['01/01/2003', '02/01/2003','03/01/2003','04/01/2003','05/01/2003','06/01/2003','07/01/2003','08/01/2003','09/01/2003','10/01/2003','11/01/2003'],
markers: {
  size: 0
},
xaxis: {
  type:'datetime'
},
yaxis: {
  title: {
    text: 'Points',
  },
  min: 0
},
legend: {
  show: false
},
tooltip: {
  shared: true,
  intersect: false,
  y: {
    formatter: function (y) {
      if(typeof y !== "undefined") {
        return  y.toFixed(0) + " points";
      }
      return y;
    }
  }
}

vanilla-js-script:
// The chart is already rendered here, so wire the checkboxes straight away.
// (wireCustomLegend lives in the shared head script.)
wireCustomLegend()

react-script:
React.useEffect(() => {
  // The react-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id. Poll until it exists, then wire the same checkbox legend the
  // vanilla build does. (wireCustomLegend lives in the shared head script.)
  let cleanup
  const timer = window.setInterval(() => {
    cleanup = wireCustomLegend()
    if (cleanup) window.clearInterval(timer)
  }, 50)

  return () => {
    window.clearInterval(timer)
    if (cleanup) cleanup()
  }
}, [])

vue-script:
mounted: function () {
  // The vue-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id. Poll until it exists, then wire the same checkbox legend the
  // vanilla build does. (wireCustomLegend lives in the shared head script.)
  var me = this
  var timer = window.setInterval(function () {
    me.legendCleanup = wireCustomLegend()
    if (me.legendCleanup) window.clearInterval(timer)
  }, 50)
},
beforeDestroy: function () {
  if (this.legendCleanup) this.legendCleanup()
},
